321→    private fun onReaderTagClicked(tag: String) {
322→        launch(ioDispatcher) {
323→            readerTracker.track(AnalyticsTracker.Stat.READER_DISCOVER_TOPIC_TAPPED)
324→            val readerTag = readerUtilsWrapper.getTagFromTagName(tag, FOLLOWED)
325→            _navigationEvents.postValue(Event(ShowPostsByTag(readerTag)))
326→        }
327→    }
